const body = $json.body || $json;
const data = body.data || body;
const key = data.key || {};
const message = data.message || {};

const remoteJid = key.remoteJid || data.remoteJid || data.from || body.from || '';
const instance = body.instance || data.instance || $env.EVOLUTION_INSTANCE || 'default';
const messageId = key.id || data.messageId || body.messageId || '';

let text = '';
let messageType = 'unknown';
let mediaUrl = '';
let caption = '';

if (message.conversation) {
  text = message.conversation;
  messageType = 'text';
} else if (message.extendedTextMessage?.text) {
  text = message.extendedTextMessage.text;
  messageType = 'text';
} else if (message.audioMessage) {
  messageType = 'audio';
  mediaUrl = message.audioMessage.url || data.mediaUrl || data.url || '';
} else if (message.imageMessage) {
  messageType = 'image';
  mediaUrl = message.imageMessage.url || data.mediaUrl || data.url || '';
  caption = message.imageMessage.caption || '';
  text = caption;
} else if (data.messageType) {
  const mt = String(data.messageType).toLowerCase();
  if (mt === 'conversation' || mt === 'extendedtextmessage' || mt === 'text') {
    messageType = 'text';
    text = data.text || data.body || '';
  } else if (mt.includes('audio')) {
    messageType = 'audio';
    mediaUrl = data.mediaUrl || data.url || '';
  } else if (mt.includes('image')) {
    messageType = 'image';
    mediaUrl = data.mediaUrl || data.url || '';
    caption = data.caption || '';
    text = caption;
  } else {
    messageType = mt;
    text = data.text || data.body || '';
  }
}

return [
  {
    json: {
      raw: body,
      event: body.event || data.event || '',
      instance,
      remoteJid,
      messageId,
      messageType,
      text: String(text || '').trim(),
      mediaUrl,
      caption,
      isFromMe: Boolean(key.fromMe)
    }
  }
];

